#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
int n,m,dp[105][105],b[105][105],ans;
struct node
{
	ll x,y,num;
	bool operator<(const node other) const
	{
		return num<other.num;
	}
} a[10005];
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
            cin>>b[i][j];
			a[(i-1)*m+j]=node{i,j,b[i][j]};
		}
	}
	sort(a+1,a+1+n*m);
	for(int i=1;i<=n*m;i++)
	{
		int x=a[i].x,y=a[i].y;
		// dp[x][y]=max(dp[x][y-1],max(dp[x][y+1],max(dp[x+1][y],dp[x-1][y])))+1;
        dp[x][y]=1;
        if(b[x][y-1]!=b[x][y]) dp[x][y]=max(dp[x][y],dp[x][y-1]+1);
        if(b[x][y+1]!=b[x][y]) dp[x][y]=max(dp[x][y],dp[x][y+1]+1);
        if(b[x-1][y]!=b[x][y]) dp[x][y]=max(dp[x][y],dp[x-1][y]+1);
        if(b[x+1][y]!=b[x][y]) dp[x][y]=max(dp[x][y],dp[x+1][y]+1);
		ans=max(ans,dp[x][y]);
	}
	cout<<ans;
	return 0;
}
